"use client"
import Link from "next/link";
import { usePathname } from "next/navigation";
import { cn } from "@/lib/utils";
import { 
  LayoutDashboard, 
  PenLine, 
  History, 
  MessageSquareWarning, 
  BookOpen,
  Users,
  Settings,
  Bell,
  LogOut,
  Brain
} from "lucide-react";
import { Button } from "../ui/button";

interface SidebarProps {
  role: "student" | "counselor" | "admin";
}

export function Sidebar({ role }: SidebarProps) {
  const pathname = usePathname();

  const links = {
    student: [
      { href: "/dashboard/student", label: "Dashboard", icon: LayoutDashboard },
      { href: "/dashboard/student/tracker", label: "Daily Mood", icon: PenLine },
      { href: "/dashboard/student/history", label: "Riwayat", icon: History },
      { href: "/dashboard/student/whisper", label: "Whisper Portal", icon: MessageSquareWarning },
      { href: "/dashboard/student/resources", label: "Edukasi", icon: BookOpen },
    ],
    counselor: [
      { href: "/dashboard/counselor", label: "Overview", icon: LayoutDashboard },
      { href: "/dashboard/counselor/students", label: "Daftar Siswa", icon: Users },
      { href: "/dashboard/counselor/alerts", label: "Peringatan Dini", icon: Bell },
      { href: "/dashboard/counselor/counseling", label: "Sesi Konseling", icon: BookOpen },
    ],
    admin: [
      { href: "/dashboard/admin", label: "Overview", icon: LayoutDashboard },
      { href: "/dashboard/admin/users", label: "Manajemen Akun", icon: Users },
      { href: "/dashboard/admin/school", label: "Data Sekolah", icon: BookOpen },
      { href: "/dashboard/admin/settings", label: "Pengaturan", icon: Settings },
    ]
  };

  const currentLinks = links[role] || links.student;
  
  const roleDisplay = {
    student: "Siswa",
    counselor: "Guru BK",
    admin: "Admin"
  }[role];

  return (
    <aside className="fixed left-0 top-0 z-40 h-screen w-64 border-r bg-card shadow-sm transition-transform -translate-x-full sm:translate-x-0 hidden md:block">
      <div className="flex h-full flex-col overflow-y-auto px-4 py-6">
        <Link href="/" className="flex items-center space-x-2 mb-8 px-2">
          <Brain className="w-8 h-8 text-primary" />
          <span className="text-2xl font-bold tracking-tight text-primary">Mind<span className="text-foreground">Guard</span></span>
        </Link>

        <div className="mb-6 px-2">
          <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">
            Menu {roleDisplay}
          </p>
        </div>

        <nav className="flex-1 space-y-2">
          {currentLinks.map((item) => {
            const Icon = item.icon;
            const isActive = pathname === item.href;
            return (
              <Link key={item.href} href={item.href}>
                <Button
                  variant={isActive ? "secondary" : "ghost"}
                  className={cn(
                    "w-full justify-start transition-all",
                    isActive ? "bg-primary/10 text-primary hover:bg-primary/20 hover:text-primary font-semibold" : "text-muted-foreground hover:bg-secondary/10"
                  )}
                >
                  <Icon className={cn("mr-3 h-5 w-5", isActive ? "text-primary" : "")} />
                  {item.label}
                </Button>
              </Link>
            )
          })}
        </nav>

        <div className="mt-auto pt-6 border-t border-border">
          <Link href="/">
            <Button variant="ghost" className="w-full justify-start text-destructive hover:bg-destructive/10 hover:text-destructive">
              <LogOut className="mr-3 h-5 w-5" />
              Keluar
            </Button>
          </Link>
        </div>
      </div>
    </aside>
  );
}
