"use client"
import { useState } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { CheckCircle2 } from "lucide-react";

const moodScale = [
  { value: 1, emoji: "😢", label: "Sangat Buruk", color: "hover:bg-destructive/20 hover:border-destructive text-destructive" },
  { value: 2, emoji: "😞", label: "Buruk", color: "hover:bg-orange-500/20 hover:border-orange-500 text-orange-500" },
  { value: 3, emoji: "😐", label: "Netral", color: "hover:bg-yellow-500/20 hover:border-yellow-500 text-yellow-600 dark:text-yellow-500" },
  { value: 4, emoji: "🙂", label: "Baik", color: "hover:bg-emerald-500/20 hover:border-emerald-500 text-emerald-500" },
  { value: 5, emoji: "🤩", label: "Sangat Baik", color: "hover:bg-primary/20 hover:border-primary text-primary" },
];

export default function DailyMoodTracker() {
  const [selectedMood, setSelectedMood] = useState<number | null>(null);
  const [note, setNote] = useState("");
  const [isSubmitted, setIsSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedMood) {
      setIsSubmitted(true);
      // Timeout to simulate API call
      setTimeout(() => {
        // Here we could redirect or show success state
      }, 1000);
    }
  };

  return (
    <DashboardLayout role="student">
      <div className="max-w-2xl mx-auto space-y-6 mt-8">
        <div>
          <h1 className="text-3xl font-bold tracking-tight text-center">Daily Mood Tracker</h1>
          <p className="text-muted-foreground mt-2 text-center">Catat bagaimana perasaanmu hari ini, agar kami bisa membantu memantaunya.</p>
        </div>

        {isSubmitted ? (
          <Card className="border-primary/20 bg-primary/5 py-12 text-center animate-in fade-in slide-in-from-bottom-4 duration-500">
            <CardContent className="flex flex-col items-center justify-center space-y-4">
              <div className="rounded-full bg-primary/20 p-4">
                <CheckCircle2 className="w-16 h-16 text-primary" />
              </div>
              <h2 className="text-2xl font-bold">Terima Kasih!</h2>
              <p className="text-muted-foreground max-w-sm">Mencatat perasaan adalah langkah pertama yang hebat untuk memahami diri sendiri lebih baik.</p>
              <Button onClick={() => setIsSubmitted(false)} variant="outline" className="mt-4">
                Perbarui Mood
              </Button>
            </CardContent>
          </Card>
        ) : (
          <form onSubmit={handleSubmit}>
            <Card className="shadow-lg border-primary/10 transition-all duration-300">
              <CardHeader className="text-center pb-8 border-b bg-muted/30">
                <CardTitle className="text-2xl">Bagaimana perasaanmu sekarang?</CardTitle>
                <CardDescription>Pilih salah satu emoji yang paling mewakili.</CardDescription>
              </CardHeader>
              
              <CardContent className="pt-8 space-y-8">
                <div className="flex justify-between items-center px-2 md:px-8">
                  {moodScale.map((mood) => {
                    const isSelected = selectedMood === mood.value;
                    return (
                      <button
                        key={mood.value}
                        type="button"
                        onClick={() => setSelectedMood(mood.value)}
                        className={cn(
                          "group flex flex-col items-center space-y-3 p-4 rounded-2xl transition-all duration-300 border-2 border-transparent",
                          mood.color,
                          isSelected && "scale-110 shadow-lg"
                        )}
                        style={{
                          borderColor: isSelected ? 'currentColor' : 'transparent',
                          backgroundColor: isSelected ? 'var(--tw-gradient-from)' : 'transparent' // Using current theme color roughly
                        }}
                      >
                        <span className={cn(
                          "text-5xl md:text-6xl filter transition-all",
                          isSelected ? "grayscale-0" : "grayscale opacity-50 group-hover:grayscale-0 group-hover:opacity-100"
                        )}>
                          {mood.emoji}
                        </span>
                        <span className={cn(
                          "text-xs md:text-sm font-medium opacity-0 group-hover:opacity-100 transition-opacity",
                          isSelected && "opacity-100"
                        )}>
                          {mood.label}
                        </span>
                      </button>
                    );
                  })}
                </div>

                <div className="space-y-3 pt-4 border-t border-border">
                  <label htmlFor="notes" className="text-sm font-medium">Tambah Catatan Jurnal (Opsional)</label>
                  <textarea
                    id="notes"
                    value={note}
                    onChange={(e) => setNote(e.target.value)}
                    placeholder="Apa yang membuatmu merasa seperti ini? Bebaskan pikiranmu di sini..."
                    className="w-full min-h-[120px] rounded-md border border-input bg-background/50 px-3 py-2 text-sm shadow-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
                  />
                  <p className="text-xs text-muted-foreground">Catatan ini pribadi dan dapat membantumu memahami pemicu emosimu dari waktu ke waktu.</p>
                </div>
              </CardContent>

              <CardFooter className="bg-muted/30 pt-6">
                <Button 
                  type="submit" 
                  className="w-full h-12 text-lg font-medium" 
                  disabled={!selectedMood}
                >
                  Simpan Mood Hari Ini
                </Button>
              </CardFooter>
            </Card>
          </form>
        )}
      </div>
    </DashboardLayout>
  );
}
